SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for sc_affair_template
-- ----------------------------
DROP TABLE IF EXISTS `sc_affair_template`;
CREATE TABLE `sc_affair_template`  (
  `template_id` bigint NOT NULL AUTO_INCREMENT COMMENT '模板ID',
  `category_id` bigint NOT NULL COMMENT '事务分类ID',
  `template_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '模板编码',
  `template_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '模板名称',
  `business_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '业务编码',
  `business_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '业务名称',
  `audience_roles` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'student' COMMENT '可发起角色',
  `form_schema_json` json NULL COMMENT '表单Schema',
  `workflow_schema_json` json NULL COMMENT '流程Schema',
  `allow_attachment` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '是否允许附件（0否 1是）',
  `allow_revoke` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '1' COMMENT '是否允许撤回（0否 1是）',
  `apply_scope_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '申请范围配置JSON',
  `business_rules_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '业务规则配置JSON',
  `target_status_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '目标学籍状态编码',
  `target_status_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '目标学籍状态名称',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '状态（0正常 1停用）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '备注',
  PRIMARY KEY (`template_id`) USING BTREE,
  UNIQUE INDEX `uk_sc_affair_template_code`(`template_code` ASC) USING BTREE,
  INDEX `idx_sc_affair_template_category_id`(`category_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 18 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '学生事务模板表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sc_affair_template
-- ----------------------------
INSERT INTO `sc_affair_template` VALUES (1, 1, 'ASK_LEAVE_STANDARD', '学生请销假申请', 'ASK_LEAVE_STANDARD', '学生请销假申请', 'student', '[{\"field\": \"leaveType\", \"label\": \"请假类型\", \"options\": [{\"label\": \"事假\", \"value\": \"PERSONAL\"}, {\"label\": \"病假\", \"value\": \"SICK\"}, {\"label\": \"公假\", \"value\": \"OFFICIAL\"}], \"required\": true, \"component\": \"select\"}, {\"field\": \"startDate\", \"label\": \"开始时间\", \"required\": true, \"component\": \"date\"}, {\"field\": \"endDate\", \"label\": \"结束时间\", \"required\": true, \"component\": \"date\"}, {\"field\": \"destination\", \"label\": \"去向地点\", \"required\": true, \"component\": \"input\"}, {\"field\": \"emergencyContact\", \"label\": \"紧急联系人\", \"required\": true, \"component\": \"input\"}, {\"field\": \"reason\", \"label\": \"申请说明\", \"required\": true, \"component\": \"textarea\"}]', '[{\"stepCode\": \"advisor_review\", \"stepName\": \"辅导员审核\", \"reviewerRole\": \"advisor\", \"assignmentType\": \"ROLE\"}]', '1', '1', '{\"scopeType\":\"ALL\",\"deptIds\":[],\"gradeIds\":[],\"classIds\":[],\"userIds\":[]}', '{\"requireNoPending\":true}', '', '', 1, '0', 'admin', '2026-03-28 16:21:04', '', NULL, '学生请销假默认模板');
