INSERT INTO `sc_affair_template` VALUES (9, 9, 'TEXTBOOK_APPLY', '教材申请', 'TEXTBOOK_APPLY', '教材申请', 'student,teacher', '[{\"field\": \"textbookType\", \"label\": \"办理类型\", \"options\": [{\"label\": \"教材领用\", \"value\": \"CLAIM\"}, {\"label\": \"教材补领\", \"value\": \"REISSUE\"}, {\"label\": \"教材征订\", \"value\": \"ORDER\"}], \"required\": true, \"component\": \"select\"}, {\"field\": \"courseId\", \"label\": \"对应课程\", \"required\": true, \"component\": \"select\", \"optionSource\": \"myCourses\", \"hintText\": \"请选择教材对应的课程\"}, {\"field\": \"isbn\", \"label\": \"ISBN/教材编号\", \"required\": true, \"component\": \"input\", \"hintText\": \"请填写教材封底的ISBN编号\"}, {\"field\": \"quantity\", \"label\": \"数量\", \"required\": true, \"component\": \"number\", \"hintText\": \"每次申请最多10本\"}, {\"field\": \"reason\", \"label\": \"申请说明\", \"required\": false, \"component\": \"textarea\", \"hintText\": \"如为补领请说明原因，征订请说明需求\"}]', '[{\"stepCode\": \"advisor_review\", \"stepName\": \"辅导员审核\", \"reviewerRole\": \"advisor\", \"assignmentType\": \"ROLE\"}, {\"stepCode\": \"admin_review\", \"stepName\": \"教务审核\", \"reviewerRole\": \"admin\", \"assignmentType\": \"ROLE\"}]', '1', '1', '{\"scopeType\":\"ALL\",\"deptIds\":[],\"gradeIds\":[],\"classIds\":[],\"userIds\":[]}', '{\"requireNoPending\":true}', '', '', 9, '0', 'admin', '2026-03-28 16:21:04', '', NULL, '教材模板');
