INSERT INTO `sc_affair_template` VALUES (17, 2, 'LEAVE_RETURN_CONFIRM', '返校登记', 'LEAVE_RETURN_CONFIRM', '返校登记', 'student', '[{\"field\": \"leaveRequestNo\", \"label\": \"离校申请编号\", \"required\": true, \"component\": \"select\", \"optionSource\": \"myLeaveReturnRequests\", \"hintText\": \"仅显示已审批通过且尚未登记返校的离校申请\"}, {\"field\": \"returnDate\", \"label\": \"返校日期\", \"required\": true, \"component\": \"date\"}, {\"field\": \"travelSummary\", \"label\": \"行程说明\", \"hintText\": \"请填写返校交通方式、返校时间及需要说明的信息。\", \"required\": true, \"component\": \"textarea\"}]', '[{\"stepCode\": \"advisor_review\", \"stepName\": \"辅导员确认\", \"reviewerRole\": \"advisor\", \"assignmentType\": \"ROLE\"}]', '0', '1', '{\"scopeType\":\"ALL\",\"deptIds\":[],\"gradeIds\":[],\"classIds\":[],\"userIds\":[]}', '{\"requireNoPending\":true}', '', '', 3, '0', 'admin', '2026-03-28 20:09:07', '', NULL, '离返校场景下的返校登记模板');
INSERT INTO `sc_affair_template` VALUES (18, 11, 'ACADEMIC_STATUS_WITHDRAW', '学籍异动-退学', 'ACADEMIC_STATUS_WITHDRAW', '退学申请', 'student', '[{\"field\": \"withdrawType\", \"label\": \"退学类型\", \"required\": true, \"component\": \"select\", \"options\": [{\"label\": \"自愿退学\", \"value\": \"VOLUNTARY\"}, {\"label\": \"学业退学\", \"value\": \"ACADEMIC\"}, {\"label\": \"健康原因\", \"value\": \"HEALTH\"}, {\"label\": \"经济原因\", \"value\": \"FINANCIAL\"}, {\"label\": \"其他\", \"value\": \"OTHER\"}]}, {\"field\": \"effectiveDate\", \"label\": \"生效日期\", \"required\": true, \"component\": \"date\"}, {\"field\": \"reason\", \"label\": \"退学原因\", \"required\": true, \"component\": \"textarea\", \"hintText\": \"请详细说明退学原因，包括主要考虑因素及个人规划\"}, {\"field\": \"guardianName\", \"label\": \"监护人姓名\", \"required\": true, \"component\": \"input\"}, {\"field\": \"guardianPhone\", \"label\": \"监护人联系电话\", \"required\": true, \"component\": \"input\", \"hintText\": \"退学手续办理期间需保持畅通\"}, {\"field\": \"guardianOpinion\", \"label\": \"家长/监护人意见\", \"required\": true, \"component\": \"textarea\", \"hintText\": \"请填写家长或监护人对退学的知情及意见情况\"}, {\"field\": \"dormCheckout\", \"label\": \"是否已办理宿舍退宿\", \"required\": true, \"component\": \"select\", \"options\": [{\"label\": \"已办理\", \"value\": \"YES\"}, {\"label\": \"未办理\", \"value\": \"NO\"}]}, {\"field\": \"libraryCleared\", \"label\": \"是否已归还图书馆借阅物品\", \"required\": true, \"component\": \"select\", \"options\": [{\"label\": \"已归还\", \"value\": \"YES\"}, {\"label\": \"未归还/无借阅\", \"value\": \"NO\"}]}]', '[{\"stepCode\": \"advisor_review\", \"stepName\": \"辅导员审核\", \"reviewerRole\": \"advisor\", \"assignmentType\": \"ROLE\"}, {\"stepCode\": \"dept_review\", \"stepName\": \"学院审核\", \"reviewerRole\": \"admin\", \"assignmentType\": \"ROLE\"}, {\"stepCode\": \"admin_review\", \"stepName\": \"学籍管理部门审核\", \"reviewerRole\": \"admin\", \"assignmentType\": \"ROLE\"}]', '1', '1', '{\"scopeType\":\"ALL\",\"deptIds\":[],\"gradeIds\":[],\"classIds\":[],\"userIds\":[]}', '{\"requireNoPending\":true}', 'WITHDRAWN', '退学', 14, '0', 'admin', '2026-03-31 10:00:00', '', NULL, '学籍异动退学模板');
INSERT INTO `sc_affair_template` VALUES (19, 11, 'ACADEMIC_STATUS_RETAIN', '学籍异动-保留学籍', 'ACADEMIC_STATUS_RETAIN', '保留学籍申请', 'student', '[{\"field\": \"retainReason\", \"label\": \"保留学籍原因\", \"required\": true, \"component\": \"select\", \"options\": [{\"label\": \"应征入伍\", \"value\": \"MILITARY\"}, {\"label\": \"创业\", \"value\": \"ENTREPRENEURSHIP\"}, {\"label\": \"身体原因\", \"value\": \"HEALTH\"}, {\"label\": \"其他\", \"value\": \"OTHER\"}]}, {\"field\": \"retainDuration\", \"label\": \"申请保留时长\", \"required\": true, \"component\": \"select\", \"options\": [{\"label\": \"1年\", \"value\": \"1\"}, {\"label\": \"2年\", \"value\": \"2\"}], \"hintText\": \"保留学籍一般最长不超过2年\"}, {\"field\": \"effectiveDate\", \"label\": \"生效日期\", \"required\": true, \"component\": \"date\"}, {\"field\": \"reason\", \"label\": \"详细说明\", \"required\": true, \"component\": \"textarea\", \"hintText\": \"请详细说明保留学籍的具体原因及计划返校时间\"}, {\"field\": \"guardianName\", \"label\": \"监护人姓名\", \"required\": true, \"component\": \"input\"}, {\"field\": \"guardianPhone\", \"label\": \"监护人联系电话\", \"required\": true, \"component\": \"input\"}, {\"field\": \"contactAddress\", \"label\": \"保留学籍期间联系地址\", \"required\": true, \"component\": \"input\", \"hintText\": \"请填写保留学籍期间的常住地址，便于学校联系\"}]', '[{\"stepCode\": \"advisor_review\", \"stepName\": \"辅导员审核\", \"reviewerRole\": \"advisor\", \"assignmentType\": \"ROLE\"}, {\"stepCode\": \"admin_review\", \"stepName\": \"学院审核\", \"reviewerRole\": \"admin\", \"assignmentType\": \"ROLE\"}]', '1', '1', '{\"scopeType\":\"ALL\",\"deptIds\":[],\"gradeIds\":[],\"classIds\":[],\"userIds\":[]}', '{\"requireNoPending\":true}', 'RETAINED', '保留学籍', 15, '0', 'admin', '2026-03-31 10:00:00', '', NULL, '学籍异动保留学籍模板');

